path = 'exp8_csv_small/csv/urban_air_quality_sensors_1_1.csv'
print("CSV path:", path)
rows = []
with open(path) as f:
    reader = csv.DictReader(f)
    header = reader.fieldnames
    rows = list(reader)
print("rows:", len(rows))
# sensors
sensor_col = None
for c in header:
    if c.lower() in ('sensor_id','sensor','sensorid'):
        sensor_col = c; break
if sensor_col:
    sensors = sorted({r[sensor_col] for r in rows})
    print("sensors:", len(sensors))
else:
    print("sensors: unknown (no sensor_id column found)")
# pm column
pm_col = None
for c in header:
    l = c.lower()
    if any(k in l for k in ('pm25','pm-25','pm_25','pm2_5','pm2.5','pm2_5mg')):
        pm_col = c; break
if not pm_col:
    for c in header:
        if 'pm' in c.lower():
            pm_col = c; break
if not pm_col:
    print("pm25 column: not found")
else:
    print("pm_col:", pm_col)
# time column
time_col = None
for c in header:
    l = c.lower()
    if any(k in l for k in ('time','timestamp','datetime','date','hour')):
        time_col = c; break
if time_col:
    print("time_col:", time_col)
# compute diurnal
if pm_col and time_col:
    from collections import defaultdict
    hourly = defaultdict(list)
    import datetime
    for r in rows:
        val = r.get(pm_col)
        if val in (None, ''): continue
        try:
            v = float(val)
        except:
            continue
        t = r.get(time_col)
        if t is None: continue
        hour = None
        for fmt in ("%Y-%m-%d %H:%M:%S","%Y-%m-%d %H:%M","%Y-%m-%dT%H:%M:%S","%Y-%m-%dT%H:%M"):
            try:
                dt = datetime.datetime.strptime(t, fmt)
                hour = dt.hour
                break
            except:
                pass
        if hour is None:
            continue
        hourly[hour].append(v)
    if hourly:
        means = {h: sum(vs)/len(vs) if vs else 0 for h,vs in hourly.items()}
        if means:
            amp = max(means.values()) - min(means.values())
            print("diurnal_amplitude (max mean hour - min mean hour):", amp)
        else:
            print("diurnal_amplitude: unavailable")
    else:
        print("diurnal_amplitude: no hourly data")
else:
    print("diurnal_amplitude: skipped (missing pm_col or time_col)")
# anomalies
anom_count = None
# look for explicit anomaly column
anom_cols = [c for c in header if 'anomal' in c.lower() or 'outlier' in c.lower() or 'flag' == c.lower()]
for ac in anom_cols:
    if ac in header:
        # count true values
        cnt = sum(1 for r in rows if str(r.get(ac,'')).lower() in ('1','true','yes','y'))
        anom_count = cnt
        print("anomaly_count:", cnt, "(based on column", ac, ")")
        break
if anom_count is None:
    # fallback: simple threshold-based outliers using pm2.5
    if pm_col and time_col:
        vals = []
        for r in rows:
            v = r.get(pm_col)
            if v in (None,''): continue
            try:
                vals.append(float(v))
            except: pass
        if vals:
            import statistics
            mean = statistics.mean(vals)
            stdev = statistics.pstdev(vals) if len(vals) > 1 else 0
            thresh_high = mean + 2*stdev
            cnt = sum(1 for v in vals if v > thresh_high)
            print("anomaly_count (threshold-based):", cnt, "(above mean+2*std)")
        else:
            print("anomaly_count: unavailable")
else:
    pass
# jsons
params = []
if os.path.isdir('exp8_csv_small'):
    for f in os.listdir('exp8_csv_small'):
        if 'params' in f.lower() and f.endswith('.json'):
            try:
                with open(os.path.join('exp8_csv_small', f)) as jf:
                    params.append((f, json.load(jf)))
            except Exception as e:
                print("params json read error", f, e)
print("params_json_files_found:", [name for name,_ in params])
for name, data in params:
    print(name, "keys:", sorted(data.keys())[:5], "...")
# payload json
payloads = []
if os.path.isdir('exp8_csv_small'):
    for f in os.listdir('exp8_csv_small'):
        if 'payload' in f.lower() and f.endswith('.json'):
            try:
                with open(os.path.join('exp8_csv_small', f)) as jf:
                    payloads.append((f, json.load(jf)))
            except Exception as e:
                print("payload json read error", f, e)
print("payload_json_files_found:", [name for name,_ in payloads])

print("done")
