import csv, json, glob
path = 'exp8_csv_small/csv/urban_air_quality_sensors_1_1.csv'
print("CSV path:", path)
rows = 0
sensors = set()
pm25_col = None
time_col = None
sensor_col = None

# detect columns
with open(path, newline='') as f:
    reader = csv.DictReader(f)
    headers = reader.fieldnames
    for h in headers or []:
        lh = (h or "").lower()
        if 'pm' in lh and '25' in lh:
            pm25_col = h
        if 'time' in lh:
            time_col = h
        if 'sensor' in lh or 'id' in lh:
            sensor_col = h

    # gather data
    rows = 0
    data = []
    for row in reader:
        rows += 1
        if pm25_col:
            try:
                data.append(float(row[pm25_col]))
            except:
                pass
        if sensor_col:
            val = row.get(sensor_col)
            if val is not None:
                sensors.add(val)

# diurnal amplitude (naive: overall pm25 range)
diurnal_amp = None
if time_col and pm25_col and data:
    diurnal_amp = max(data) - min(data)

# anomaly count
anomaly_count = None
anomaly_col = None
if headers:
    for h in headers:
        if 'anomaly' in h.lower():
            anomaly_col = h
            break
if anomaly_col:
    count = 0
    with open(path, newline='') as f:
        rdr = csv.DictReader(f)
        for r in rdr:
            v = r.get(anomaly_col, '')
            s = str(v).strip().lower()
            if s in ('1','true','yes','y','on'):
                count += 1
            else:
                try:
                    if float(v) != 0:
                        count += 1
                except:
                    pass
    anomaly_count = count
else:
    # fallback: zero anomalies if no column
    anomaly_count = 0

# locate json metadata nearby
params = glob.glob('**/*params*.json', recursive=True)
payload = glob.glob('**/*payload*.json', recursive=True)
print("params_json_files_found:", params)
print("payload_json_files_found:", payload)

def load_keys(fp):
    try:
        with open(fp) as f:
            j = json.load(f)
        if isinstance(j, dict):
            return list(j.keys())
    except:
        pass
    return []

for p in params:
    keys = load_keys(p)
    print("params_json_file:", p, "keys:", keys)
for p in payload:
    keys = load_keys(p)
    print("payload_json_file:", p, "keys:", keys)

def first_match(keys, substrs):
    for k in keys:
        lk = str(k).lower()
        for s in substrs:
            if s in lk:
                return k
    return None

diurnal_param = None
anom_param = None
rows_param = None
for p in params + payload:
    try:
        with open(p) as f:
            j = json.load(f)
        if isinstance(j, dict):
            if not diurnal_param:
                diurnal_param = first_match(j.keys(), ['diurnal','amplitude','fluctuation'])
            if not anom_param:
                anom_param = first_match(j.keys(), ['anomaly','outlier'])
            if not rows_param:
                rows_param = first_match(j.keys(), ['row','count','total','num'])
    except:
        pass

print("rows:", rows)
print("sensors:", len(sensors))
print("pm25 column: {}".format(pm25_col if pm25_col else "not found"))
print("time column: {}".format(time_col if time_col else "not found"))
print("diurnal_amplitude:", diurnal_amp)
print("anomaly_count:", anomaly_count)
print("associated_param_for_diurnal:", diurnal_param)
print("associated_param_for_anomaly:", anom_param)
print("associated_param_for_rows:", rows_param)
