path = 'exp8_csv_small/csv/freight_rail_operations_1_1.csv'
print("Inspecting file:", path)

try:
    with open(path, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        cols = reader.fieldnames or []
        hp_col = None
        pj_col = None
        # detect likely column names
        for c in cols:
            lc = c.lower()
            if 'hyper' in lc and 'param' in lc and 'index' in lc:
                hp_col = c
            if 'params' in lc and 'json' in lc:
                pj_col = c
        if hp_col is None:
            for c in cols:
                if 'param' in c.lower() and 'index' in c.lower():
                    hp_col = c; break
        if pj_col is None:
            for c in cols:
                if 'params_json' in c.lower():
                    pj_col = c; break
                if 'params' in c.lower() and 'json' in c.lower():
                    pj_col = c; break
        if hp_col is None or pj_col is None:
            print("Could not locate required columns (hyper_param_index or params_json).")
            sys.exit(0)

        data = {}
        for row in reader:
            idx = row.get(hp_col)
            raw = row.get(pj_col, '')
            try:
                j = json.loads(raw)
            except Exception:
                try:
                    j = json.loads(raw.replace("'", '"'))
                except Exception:
                    j = {}
            data.setdefault(idx, []).append(j)

