        vol_count = {}
        delay_count = {}
        for idx, arr in data.items():
            for j in arr:
                if not isinstance(j, dict):
                    continue
                for k, v in j.items():
                    if not isinstance(v, (int, float)):
                        continue
                    lk = k.lower()
                    if ('volume' in lk) or ('ship' in lk) or ('daily' in lk):
                        vol_count[k] = vol_count.get(k, 0) + 1
                    if ('delay' in lk) or ('laten' in lk) or ('wait' in lk):
                        delay_count[k] = delay_count.get(k, 0) + 1

        chosen_vol = max(vol_count, key=vol_count.get) if vol_count else None
        chosen_del = max(delay_count, key=delay_count.get) if delay_count else None

        print("Hyper_param_index entries found:", sorted(data.keys(), key=lambda x: (str(x))))
        if chosen_vol:
            print("Most direct volume-control key in params_json:", chosen_vol)
        else:
            print("No volume-control key detected in params_json.")
        if chosen_del:
            print("Most direct delay-control key in params_json:", chosen_del)
        else:
            print("No delay-control key detected in params_json.")

        print("Interpretation:")
        print("- The hyper_param_index selects which param set (the JSON payload in params_json) is used for a run. Different indices swap in different numeric values for the keys identified above, thereby altering daily shipment volumes and observed delays.")
        # Show a few sample values per key
        if chosen_vol:
            samples = []
            for idx, arr in data.items():
                for j in arr:
                    if isinstance(j, dict) and chosen_vol in j:
                        val = j[chosen_vol]
                        if isinstance(val, (int, float)):
                            samples.append((idx, val))
                        break
            if samples:
                print("Sample volume parameter values by index (index ->", chosen_vol, "):")
                for i, (idx, val) in enumerate(samples[:6]):
                    print("  Index", idx, "->", chosen_vol, "=", val)
        if chosen_del:
            samples = []
            for idx, arr in data.items():
                for j in arr:
                    if isinstance(j, dict) and chosen_del in j:
                        val = j[chosen_del]
