t_vals = sorted({extract_int_by_keys(r, total_keys) for r in rows if extract_int_by_keys(r, total_keys) is not None})

print('Observed hyper_param_index values:', h_vals)
print('Observed total_hyper_params values:', t_vals)

# Identify possible JSON columns
param_col = next((c for c in header if c.lower() in ('params_json','params','params_json_str')), None)
payload_col = next((c for c in header if c.lower() in ('payload_json','payload','payload_json_str','payload')), None)

